async (params, browser) => {
  // Search Google Flights
  await browser.open(`https://www.google.com/travel/flights?q=${params.from}+to+${params.to}`)

  // Wait for flight results
  await browser.waitForSelector('li.pIav2d', 20000)

  // Let page render
  await browser.wait(3000)

  // Open price graph view
  const open_price_graph = await browser.evaluate(`const priceGraphBtn = document.querySelector('button[aria-label*="Price graph"], button[aria-label*="price graph"], button[jsaction*="price_graph"], div[data-flt-ve="price_graph"] button'); if (priceGraphBtn) { priceGraphBtn.click(); return { clicked: true }; } const dateBtns = document.querySelectorAll('button[aria-label*="Date grid"], button[aria-label*="date grid"]'); if (dateBtns.length > 0) { dateBtns[0].click(); return { clicked: true, type: 'date_grid' }; } return { clicked: false }`)

  // Wait for price graph to load
  await browser.wait(3000)

  // Scroll to see price graph
  await browser.scroll({ direction: 'down', amount: 600 })

  await browser.wait(2000)

  // Extract price graph data
  const price_graph_data = await browser.evaluate(`const pricePoints = []; const graphBars = document.querySelectorAll('div[data-flt-ve="price_graph"] div[role="button"], div.JRwjBf div[role="button"], g[role="listitem"]'); graphBars.forEach((bar, i) => { if (i >= 30) return; const label = bar.getAttribute('aria-label') || bar.textContent.trim(); if (label) pricePoints.push(label); }); const calendarCells = document.querySelectorAll('td[data-value], button[aria-label*="$"], button[aria-label*="EUR"], button[aria-label*="GBP"]'); const calendarPrices = []; calendarCells.forEach((cell, i) => { if (i >= 60) return; const label = cell.getAttribute('aria-label') || cell.textContent.trim(); if (label && label.match(/\d/)) calendarPrices.push(label); }); const tipEl = document.querySelector('div.CQYfx, div[class*="price-insight"], div[class*="tip"]'); return { from: params.from, to: params.to, price_graph_points: pricePoints, calendar_prices: calendarPrices, travel_tip: tipEl ? tipEl.textContent.trim() : '', data_points_count: pricePoints.length + calendarPrices.length, url: window.location.href }`)

  return price_graph_data
}
